def group_anomaly_windows(events: list[dict[str, int]], threshold: int, max_gap: int) -> dict[int, list[tuple[int, int]]]:
    if max_gap < 0:
        raise ValueError('max_gap must be nonnegative')
    by_sensor: dict[int, list[tuple[int, int]]] = {}
    for event in events:
        start = event['start']
        end = event['end']
        if end < start:
            raise ValueError('event end before start')
        if event['severity'] >= threshold:
            by_sensor.setdefault(event['sensor'], []).append((start, end))
    result: dict[int, list[tuple[int, int]]] = {}
    for sensor in sorted(by_sensor):
        merged: list[tuple[int, int]] = []
        cur_start, cur_end = sorted(by_sensor[sensor])[0]
        for start, end in sorted(by_sensor[sensor])[1:]:
            if start - cur_end <= max_gap:
                cur_end = max(cur_end, end)
            else:
                merged.append((cur_start, cur_end))
                cur_start, cur_end = start, end
        merged.append((cur_start, cur_end))
        result[sensor] = merged
    return result
```

