def net_transfer_balances(transfers: list[tuple[str, str, int]]) -> dict[str, int]:
    balances: dict[str, int] = {}
    for source, target, amount in transfers:
        if source == target:
            raise ValueError('self transfer is not allowed')
        if amount <= 0:
            raise ValueError('transfer amount must be positive')
        balances[source] = balances.get(source, 0) - amount
        balances[target] = balances.get(target, 0) + amount
    return {name: balances[name] for name in sorted(balances) if balances[name] != 0}
